import React, { useState } from 'react';

function Login() {
  // 1. State untuk menampung input user
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  // 2. Fungsi untuk menangani proses Login
  const handleLogin = async (e) => {
    e.preventDefault(); 

    try {
      const response = await fetch('http://127.0.0.1:5000/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          email: email, 
          password: password 
        }),
      });

      const result = await response.json();

      if (response.ok) {
        // --- 🚩 BAGIAN PENTING: MENYIMPAN DATA KE MEMORI BROWSER ---
        localStorage.setItem("email_aktif", email);
        localStorage.setItem("nama_aktif", result.user);
        // ----------------------------------------------------------

        alert("Login Berhasil! Selamat Datang " + result.user);

        // Pindah ke halaman dashboard
        window.location.href = "/dashboard"; 
      } else {
        alert(result.message || "Email atau Password Salah");
      }
    } catch (error) {
      console.error("Error Login:", error);
      alert("Gagal terhubung ke Backend. Pastikan Flask sudah jalan!");
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.loginCard}>
        <h2 style={styles.title}>Login Admin</h2>
        <p style={styles.subtitle}>Smart Trash Bin System</p>

        <form onSubmit={handleLogin}>
          <div style={styles.inputGroup}>
            <input 
              type="email" 
              placeholder="Email Address" 
              style={styles.input}
              value={email} 
              onChange={(e) => setEmail(e.target.value)} 
              required 
            />
          </div>

          <div style={styles.inputGroup}>
            <input 
              type="password" 
              placeholder="Password" 
              style={styles.input}
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              required 
            />
          </div>

          <button type="submit" style={styles.button}>Masuk Sekarang</button>
        </form>

        {/* --- 📝 TOMBOL MENUJU HALAMAN SIGN UP --- */}
        <div style={styles.signupBox}>
          <p style={styles.signupText}>Belum punya akun admin?</p>
          <a href="/register" style={styles.signupLink}>Daftar Admin Baru</a>
        </div>
      </div>
    </div>
  );
}

// 🎨 Styling yang sudah diperbarui dengan link Sign Up
const styles = {
  container: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    height: '100vh',
    backgroundColor: '#f0f2f5',
  },
  loginCard: {
    padding: '40px',
    borderRadius: '15px',
    backgroundColor: '#ffffff',
    boxShadow: '0 8px 24px rgba(0,0,0,0.1)',
    width: '100%',
    maxWidth: '400px',
    textAlign: 'center',
  },
  title: { color: '#1a1a1a', marginBottom: '10px' },
  subtitle: { color: '#666', marginBottom: '30px' },
  inputGroup: { marginBottom: '15px' },
  input: {
    width: '100%',
    padding: '12px',
    borderRadius: '8px',
    border: '1px solid #ddd',
    fontSize: '16px',
    boxSizing: 'border-box'
  },
  button: {
    width: '100%',
    padding: '12px',
    borderRadius: '8px',
    border: 'none',
    backgroundColor: '#007bff',
    color: 'white',
    fontSize: '16px',
    fontWeight: 'bold',
    cursor: 'pointer',
    marginTop: '10px'
  },
  // Style tambahan untuk link pendaftaran
  signupBox: {
    marginTop: '25px',
    paddingTop: '15px',
    borderTop: '1px solid #eee'
  },
  signupText: {
    fontSize: '14px',
    color: '#666',
    marginBottom: '5px'
  },
  signupLink: {
    fontSize: '14px',
    color: '#007bff',
    textDecoration: 'none',
    fontWeight: 'bold'
  }
};

export default Login;
